def solve(temperature_celsius, heart_rate, respiratory_rate, paco2, wbc, bands_percentage):
    # Step 1: evaluate_temperature_criterion
    # Determine if the temperature criterion is met (>38°C or <36°C)
    if temperature_celsius > 38 or temperature_celsius < 36:
        temperature_met = 1
    else:
        temperature_met = 0
    yield {
        "step_name": "evaluate_temperature_criterion",
        "step_description": "Determine if the temperature criterion is met (>38°C or <36°C) based on body temperature in Celsius",
        "step_result": temperature_met,
        "unit": None
    }

    # Step 2: evaluate_heart_rate_criterion
    # Determine if the heart rate criterion is met (>90 bpm)
    if heart_rate > 90:
        heart_rate_met = 1
    else:
        heart_rate_met = 0
    yield {
        "step_name": "evaluate_heart_rate_criterion",
        "step_description": "Determine if the heart rate criterion is met (>90 bpm) based on heart rate in beats per minute",
        "step_result": heart_rate_met,
        "unit": None
    }

    # Step 3: evaluate_respiratory_criterion
    # Determine if the respiratory criterion is met (respiratory rate >20 or PaCO2 <32 mm Hg)
    if respiratory_rate > 20 or (paco2 is not None and paco2 < 32):
        respiratory_met = 1
    else:
        respiratory_met = 0
    yield {
        "step_name": "evaluate_respiratory_criterion",
        "step_description": "Determine if the respiratory criterion is met (respiratory rate >20 or PaCO2 <32 mm Hg) based on respiratory rate and PaCO2",
        "step_result": respiratory_met,
        "unit": None
    }

    # Step 4: evaluate_wbc_criterion
    # Determine if the WBC criterion is met (WBC >12,000/mm3, <4,000/mm3, or >10% bands)
    if wbc > 12000 or wbc < 4000 or (bands_percentage is not None and bands_percentage > 10):
        wbc_met = 1
    else:
        wbc_met = 0
    yield {
        "step_name": "evaluate_wbc_criterion",
        "step_description": "Determine if the WBC criterion is met (WBC >12,000/mm3, <4,000/mm3, or >10% bands) based on WBC count and band percentage",
        "step_result": wbc_met,
        "unit": None
    }

    # Step 5: sum_sirs_scores
    # Sum the individual SIRS criterion scores to determine the total number of criteria met
    total_sirs = temperature_met + heart_rate_met + respiratory_met + wbc_met
    yield {
        "step_name": "sum_sirs_scores",
        "step_description": "Sum the individual SIRS criterion scores (temperature, heart rate, respiratory, WBC) to determine total number of criteria met",
        "step_result": total_sirs,
        "unit": None
    }

    return total_sirs
